const lead = $input.item.json;
const data = lead.body ?? lead;
const validation = { isValid: true, errors: [], warnings: [], sanitized: {} };
const fields = data.data?.fields || data.fields || [];
const fieldMap = {};

if (Array.isArray(fields)) {
  fields.forEach(field => {
    const label = (field.label || '').toLowerCase().trim();
    const value = (field.value || '').toString().trim();
    fieldMap[label] = value;
  });
}

const email = (fieldMap['email'] || fieldMap['email address'] || '').toLowerCase().trim();
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

if (!email) {
  validation.errors.push('Email is required');
  validation.isValid = false;
} else if (!emailRegex.test(email)) {
  validation.errors.push(`Invalid email format: ${email}`);
  validation.isValid = false;
}

validation.sanitized.email = email;

const name = (fieldMap['name'] || fieldMap['first name'] || '').trim();
if (!name || name.length < 2) {
  validation.errors.push('Name is required');
  validation.isValid = false;
}

validation.sanitized.name = name;

const company = (fieldMap['company'] || fieldMap['company name'] || '').trim();
if (!company || company.length < 2) {
  validation.errors.push('Company name is required');
  validation.isValid = false;
}

validation.sanitized.company = company;
validation.sanitized.employees = parseInt((fieldMap['employees'] || '0').replace(/[^0-9]/g, '')) || 0;
validation.sanitized.industry = (fieldMap['industry'] || '').trim();
validation.sanitized.phone = (fieldMap['phone'] || '').trim();
validation.sanitized.message = (fieldMap['message'] || '').trim();
validation.sanitized.title = (fieldMap['title'] || '').trim();
validation.sanitized.website = (fieldMap['website'] || '').trim();
validation.sanitized.country = (fieldMap['country'] || '').trim();
validation.sanitized.source = data.source || 'webhook';
validation.sanitized.receivedAt = new Date().toISOString();

return { json: { validation, lead: validation.sanitized } };

const lead = $json.lead;
const recentLeads = $input.all().slice(-100);
const duplicationCheck = { isDuplicate: false, duplicateOf: null, suspiciousPatterns: [], riskScore: 0 };

const emailDuplicates = recentLeads.filter(item => item.json?.lead?.email === lead.email);
if (emailDuplicates.length > 0) {
  duplicationCheck.isDuplicate = true;
  duplicationCheck.duplicateOf = emailDuplicates[0].json?.lead?.name;
  duplicationCheck.riskScore += 50;
}

return { json: { ...duplicationCheck, riskLevel: duplicationCheck.riskScore >= 50 ? 'high' : 'low' } };

const lead = $json.lead;
const scoreBreakdown = { baseScore: 0, industryScore: 0, companySizeScore: 0, totalScore: 0, factors: [] };

const targetIndustries = { 'healthcare': 100, 'health': 100, 'medical': 95, 'finance': 85, 'technology': 70, 'consulting': 65 };
scoreBreakdown.industryScore = targetIndustries[lead.industry?.toLowerCase()] || 30;

const employees = lead.employees || 0;
if (employees >= 1000) scoreBreakdown.companySizeScore = 100;
else if (employees >= 500) scoreBreakdown.companySizeScore = 90;
else if (employees >= 200) scoreBreakdown.companySizeScore = 80;
else scoreBreakdown.companySizeScore = 40;

scoreBreakdown.baseScore = (scoreBreakdown.industryScore * 0.5) + (scoreBreakdown.companySizeScore * 0.5);
scoreBreakdown.totalScore = Math.round(scoreBreakdown.baseScore);

return { json: scoreBreakdown };

const score = $json.totalScore;
const qualification = { tier: '', status: '', priority: '' };

if (score >= 80) {
  qualification.tier = 'Tier 1 - Highly Qualified';
  qualification.status = 'ready_for_sales';
  qualification.priority = 'CRITICAL';
} else if (score >= 60) {
  qualification.tier = 'Tier 2 - Qualified';
  qualification.status = 'sales_ready';
  qualification.priority = 'HIGH';
} else {
  qualification.tier = 'Tier 3 - Warm Lead';
  qualification.status = 'nurture';
  qualification.priority = 'MEDIUM';
}

return { json: qualification };

const lead = $input.all()[0].json.lead;
const scoring = $input.all()[1].json;
const qualification = $input.all()[2].json;

const now = new Date();
const leadProfile = {
  leadId: `LEAD-${now.getTime()}`,
  contact: { name: lead.name, email: lead.email, phone: lead.phone, title: lead.title },
  company: { name: lead.company, employees: lead.employees, industry: lead.industry },
  scoring: { totalScore: scoring.totalScore, breakdown: { industry: scoring.industryScore, companySize: scoring.companySizeScore } },
  qualification: qualification,
  audit: { receivedAt: lead.receivedAt, processedAt: now.toISOString(), version: '2.0.0' }
};

return { json: leadProfile };
